const isSinglePixel = (image: string[]): boolean =>
  image.length === 1 && image[0].length === 1;

const isMultiRowMultiCol = (image: string[]): boolean =>
  image.length > 1 && image[0].length > 1;

const isSingleColumn = (image: string[]): boolean =>
  image.length > 1 && image.every((line) => line.length === 1);

export function scale(image: string[], scaleFactor: number): string[] {
  if (image.length === 0) {
    return [];
  }

  const needsHorizontalScaling = isMultiRowMultiCol(image);
  const needsVerticalScaling = isSinglePixel(image) || isSingleColumn(image);

  if (!needsHorizontalScaling && needsVerticalScaling) {
    // Scale vertically only (single pixel or single column)
    return duplicateLines(image, scaleFactor);
  }

  if (needsHorizontalScaling) {
    // Scale both horizontally and vertically
    const horizontallyScaled = scaleHorizontalLines(image, scaleFactor);
    return duplicateLines(horizontallyScaled, scaleFactor);
  }

  // Default: scale horizontally only (single row)
  return scaleHorizontalLines(image, scaleFactor);
}

